var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"저건…… 기지를 습격했던 그 괴물인가?","JPN":"あれは……基地を襲ってきた化け物か？","ENG":"Isn’t that... the monster that attacked the base?","TWN":"那是……偷襲基地的怪物嗎？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"침식파 형태가 미세하게 달라, 동형 타입의 다른 개체인 것 같아!","JPN":"侵食波の形が微妙に違う、同型タイプの他の個体みたい！","ENG":"Seeing that the Corruption ray form is slightly different, it seems to be a different entity of the same type!","TWN":"和侵蝕波型態不太一樣，應該是不同類型的個體！"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"2시 방향! 사령관님, 미확인 침식체들이 더 몰려옵니다!","JPN":"2時方向！　司令官、未確認侵食体がもっと押し寄せてきます！","ENG":"2 o’clock! Commander, more unidentified Corrupted Objects are heading our way!","TWN":"2點鐘方向！司令官，不明侵蝕體湧現！"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저 쪽은 인형들이로군요.","JPN":"あちらは人形たちですね。","ENG":"Those are puppets.","TWN":"你們那邊是木偶嗎？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"인형?","JPN":"人形？","ENG":"Puppets?","TWN":"木偶？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네, 그런 취미를 가진 마왕의 수하들입니다. 저희는 인형의 창조자라고 부르죠.","JPN":"はい、そういう趣味を持った魔王の手下たちです。私たちは人形の創造者と呼んでいます。","ENG":"Yes, they are the minions of a Demon Lord who has such a hobby. We call her the Puppet Creator.","TWN":"是，那些是喜歡木偶的魔王手下，我們稱她為木偶的創造者。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그럼 최소 두 명의 마왕이 우리 뒤를 포위했다는 뜻인가?","JPN":"それでは少なくとも2人の魔王が私たちの後ろを囲んでいるということか？","ENG":"So you’re saying that at least two Demon Lords have surrounded us from the back?","TWN":"意思是至少有二個魔王包圍我們嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"별로 기분 좋은 소식은 아니군.","JPN":"それはあまり嬉しいニュースではないな。","ENG":"I was hoping for better news.","TWN":"這不是個好消息呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저로서도 의외입니다. 마왕들이 전장에서 손을 잡는 경우는 거의 없거든요.","JPN":"こちらとしても意外ですね。魔王たちが戦場で手を組むことはほとんどないので。","ENG":"I am also surprised. Demon Lords almost never join forces on the battlefield.","TWN":"我也感到很意外，魔王在戰場上幾乎不太會聯手的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"안타깝군. 적 선두 부대를 괴멸시킬 기회였는데.","JPN":"残念だ。敵の先鋒部隊を壊滅させるチャンスだったのに。","ENG":"That is unfortunate. It was our opportunity to wipe out the enemy’s vanguard.","TWN":"真可惜，原本有機會可以殲滅敵人的先鋒部隊。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"완전히 포위 당하기 전에 이 장소를 빠져나가야겠어.","JPN":"完全に囲まれる前にこの場所から抜け出すぞ。","ENG":"We should retreat before we’re completely surrounded.","TWN":"在完全受困前，必須趕快離開這個地方。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……그건 곤란합니다.","JPN":"……それは困ります。","ENG":"...That would be difficult.","TWN":"……這可能有困難。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"무슨 뜻이지?","JPN":"どういうことだ？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 게임에는 룰이 있다고 말씀 드렸었죠.","JPN":"このゲームにはルールがあるとお話ししましたね。","ENG":"Do you remember that I mentioned there are rules to this game?","TWN":"我說過這個遊戲是有規則的。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"승리를 위한 규칙이 있다면, 패배를 위한 규칙도 있습니다.","JPN":"勝利のための規則があるなら、敗北のための規則もあります。","ENG":"If there are rules for victory, then there are rules for defeat as well.","TWN":"贏有贏的規則，輸也有輸的規則。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};